arguments.content:
import { useState } from "react";

const rubros = [
  "Restaurante / Gastronomía",
  "Salud / Medicina / Clínica",
  "Peluquería / Estética / Spa",
  "Ferretería / Construcción",
  "Óptica / Indumentaria / Retail",
  "Distribución / Logística",
  "Educación / Academia",
  "Inmobiliaria / Propiedades",
  "Contabilidad / Consultoría",
  "Servicios al hogar / Técnico",
  "E-commerce / Tienda online",
  "Agencia de Marketing",
  "Turismo / Hotelería",
  "Otro",
];

const volOptions = [
  { val: "1-20", label: "1–20 consultas/día", desc: "Negocio chico o en crecimiento" },
  { val: "21-50", label: "21–50 consultas/día", desc: "Operación mediana activa" },
  { val: "51-150", label: "51–150 consultas/día", desc: "Alta demanda de atención" },
  { val: "150+", label: "Más de 150/día", desc: "Necesitás automatización urgente" },
];

const beneficios = [
  { icon: "ti-robot", label: "Bot 24/7", desc: "Atiende mientras dormís" },
  { icon: "ti-calendar-event", label: "Turnos auto", desc: "Sin llamados ni errores" },
  { icon: "ti-chart-line", label: "ROI visible", desc: "Resultados en 30 días" },
  { icon: "ti-clock", label: "Setup en 48 hs", desc: "Nosotros lo configuramos" },
];

export default function ContactoPage() {
  const [form, setForm] = useState({
    nombre: "",
    empresa: "",
    rubro: "",
    volumen: "",
    whatsapp: "",
    mensaje: "",
  });
  const [sent, setSent] = useState(false);

  function handleChange(e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) {
    setForm(f => ({ ...f, [e.target.name]: e.target.value }));
  }

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const lines = [
      `🤖 *Solicitud de Diagnóstico Gratuito — Clientum*`,
      ``,
      `👤 *Nombre:* ${form.nombre}`,
      `🏢 *Empresa:* ${form.empresa}`,
      `📂 *Rubro:* ${form.rubro}`,
      `📊 *Volumen de consultas:* ${form.volumen}`,
      `📱 *WhatsApp:* ${form.whatsapp}`,
      form.mensaje ? `💬 *Comentario:* ${form.mensaje}` : null,
    ].filter(Boolean).join("\n");

    const url = `https://wa.me/5492984510883?text=${encodeURIComponent(lines)}`;
    window.open(url, "_blank");
    setSent(true);
  }

  const valid = form.nombre.trim() && form.empresa.trim() && form.rubro && form.volumen && form.whatsapp.trim();

  if (sent) {
    return (
      <div className="max-w-lg mx-auto mt-16 text-center">
        <div
          className="rounded-2xl p-10 flex flex-col items-center gap-4"
          style={{ background: "#0D1E3D", border: "1.5px solid rgba(196,154,44,.3)" }}
        >
          <div
            className="w-16 h-16 rounded-full flex items-center justify-center"
            style={{ background: "rgba(196,154,44,.15)", border: "2px solid rgba(196,154,44,.4)" }}
          >
            <i className="ti ti-brand-whatsapp text-3xl" style={{ color: "#C49A2C" }} />
          </div>
          <h2 className="text-xl font-extrabold text-white">¡Mensaje enviado!</h2>
          <p className="text-sm leading-relaxed" style={{ color: "rgba(255,255,255,.65)" }}>
            Te abrimos WhatsApp con tu solicitud lista. El equipo de Clientum te responde dentro de las próximas <strong className="text-white">2 horas hábiles</strong>.
          </p>
          <button
            onClick={() => setSent(false)}
            className="mt-2 text-xs font-semibold underline"
            style={{ color: "rgba(255,255,255,.4)" }}
          >
            Enviar otra solicitud
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto pb-12 space-y-6">

      {/* Hero */}
      <div
        className="rounded-2xl p-6 flex flex-col md:flex-row items-start md:items-center gap-6"
        style={{ background: "linear-gradient(135deg,#0A2558,#1B3F87)", border: "1.5px solid rgba(196,154,44,.22)" }}
      >
        <div className="flex-1">
          <div className="flex items-center gap-2 mb-3">
            <i className="ti ti-stethoscope text-base" style={{ color: "#C49A2C" }} />
            <span className="text-xs font-bold uppercase tracking-widest" style={{ color: "#C49A2C" }}>
              Diagnóstico gratuito · 45 minutos
            </span>
          </div>
          <h1 className="text-2xl font-extrabold text-white mb-2">
            Hablemos de tu empresa
          </h1>
          <p className="text-sm leading-relaxed" style={{ color: "rgba(255,255,255,.7)" }}>
            Sin compromiso, sin tarjeta, sin IT. Analizamos tu operación y te mostramos exactamente cuánto podés automatizar — y cuánto vas a ahorrar.
          </p>
        </div>
        <div className="grid grid-cols-2 gap-3 flex-shrink-0">
          {beneficios.map(b => (
            <div
              key={b.label}
              className="rounded-xl px-3 py-2.5 flex items-center gap-2"
              style={{ background: "rgba(255,255,255,.07)", border: "1px solid rgba(255,255,255,.1)" }}
            >
              <i className={`ti ${b.icon} text-sm`} style={{ color: "#C49A2C" }} />
              <div>
                <p className="text-xs font-bold text-white leading-none">{b.label}</p>
                <p className="text-[10px] mt-0.5" style={{ color: "rgba(255,255,255,.5)" }}>{b.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Form */}
      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">

        {/* Left column */}
        <div className="space-y-4">
          <div
            className="rounded-xl p-5 space-y-4"
            style={{ background: "#0D1E3D", border: "1px solid rgba(255,255,255,.07)" }}
          >
            <p className="text-xs font-bold uppercase tracking-wider" style={{ color: "rgba(255,255,255,.4)" }}>Sobre vos</p>

            <div className="space-y-1">
              <label className="text-xs font-semibold text-white">Nombre completo *</label>
              <input
                name="nombre"
                value={form.nombre}
                onChange={handleChange}
                required
                placeholder="Ej: Carlos Martínez"
                className="w-full rounded-lg px-3 py-2.5 text-sm text-white placeholder-white/30 outline-none focus:ring-1"
                style={{
                  background: "rgba(255,255,255,.06)",
                  border: "1px solid rgba(255,255,255,.1)",
                  focusRingColor: "#C49A2C",
                }}
                onFocus={e => (e.target.style.borderColor = "rgba(196,154,44,.5)")}
                onBlur={e => (e.target.style.borderColor = "rgba(255,255,255,.1)")}
              />
            </div>

            <div className="space-y-1">
              <label className="text-xs font-semibold text-white">Nombre de la empresa *</label>
              <input
                name="empresa"
                value={form.empresa}
                onChange={handleChange}
                required
                placeholder="Ej: Ferretería Don Jorge"
                className="w-full rounded-lg px-3 py-2.5 text-sm text-white placeholder-white/30 outline-none"
                style={{ background: "rgba(255,255,255,.06)", border: "1px solid rgba(255,255,255,.1)" }}
                onFocus={e => (e.target.style.borderColor = "rgba(196,154,44,.5)")}
                onBlur={e => (e.target.style.borderColor = "rgba(255,255,255,.1)")}
              />
            </div>

            <div className="space-y-1">
              <label className="text-xs font-semibold text-white">WhatsApp de contacto *</label>
              <input
                name="whatsapp"
                value={form.whatsapp}
                onChange={handleChange}
                required
                placeholder="Ej: +54 9 351 000 0000"
                type="tel"
                className="w-full rounded-lg px-3 py-2.5 text-sm text-white placeholder-white/30 outline-none"
                style={{ background: "rgba(255,255,255,.06)", border: "1px solid rgba(255,255,255,.1)" }}
                onFocus={e => (e.target.style.borderColor = "rgba(196,154,44,.5)")}
                onBlur={e => (e.target.style.borderColor = "rgba(255,255,255,.1)")}
              />
            </div>

            <div className="space-y-1">
              <label className="text-xs font-semibold text-white">Rubro *</label>
              <select
                name="rubro"
                value={form.rubro}
                onChange={handleChange}
                required
                className="w-full rounded-lg px-3 py-2.5 text-sm text-white outline-none"
                style={{
                  background: "rgba(255,255,255,.06)",
                  border: "1px solid rgba(255,255,255,.1)",
                  color: form.rubro ? "#fff" : "rgba(255,255,255,.3)",
                }}
              >
                <option value="" disabled style={{ background: "#0D1E3D" }}>Seleccioná tu rubro</option>
                {rubros.map(r => (
                  <option key={r} value={r} style={{ background: "#0D1E3D" }}>{r}</option>
                ))}
              </select>
            </div>
          </div>

          {/* Optional message */}
          <div
            className="rounded-xl p-5"
            style={{ background: "#0D1E3D", border: "1px solid rgba(255,255,255,.07)" }}
          >
            <p className="text-xs font-bold uppercase tracking-wider mb-3" style={{ color: "rgba(255,255,255,.4)" }}>Comentario (opcional)</p>
            <textarea
              name="mensaje"
              value={form.mensaje}
              onChange={handleChange}
              rows={3}
              placeholder="Describí brevemente el principal problema que querés resolver..."
              className="w-full rounded-lg px-3 py-2.5 text-sm text-white placeholder-white/30 outline-none resize-none"
              style={{ background: "rgba(255,255,255,.06)", border: "1px solid rgba(255,255,255,.1)" }}
              onFocus={e => (e.target.style.borderColor = "rgba(196,154,44,.5)")}
              onBlur={e => (e.target.style.borderColor = "rgba(255,255,255,.1)")}
            />
          </div>
        </div>

        {/* Right column — volume selector */}
        <div className="space-y-4">
          <div
            className="rounded-xl p-5"
            style={{ background: "#0D1E3D", border: "1px solid rgba(255,255,255,.07)" }}
          >
            <p className="text-xs font-bold uppercase tracking-wider mb-4" style={{ color: "rgba(255,255,255,.4)" }}>
              ¿Cuántas consultas recibís por día? *
            </p>
            <div className="space-y-2">
              {volOptions.map(opt => (
                <label
                  key={opt.val}
                  className="flex items-center gap-3 p-3 rounded-lg cursor-pointer transition-all"
                  style={{
                    background: form.volumen === opt.val ? "rgba(196,154,44,.1)" : "rgba(255,255,255,.03)",
                    border: form.volumen === opt.val ? "1.5px solid rgba(196,154,44,.4)" : "1px solid rgba(255,255,255,.07)",
                  }}
                >
                  <input
                    type="radio"
                    name="volumen"
                    value={opt.val}
                    checked={form.volumen === opt.val}
                    onChange={handleChange}
                    className="hidden"
                  />
                  <div
                    className="w-4 h-4 rounded-full flex-shrink-0 flex items-center justify-center"
                    style={{
                      border: form.volumen === opt.val ? "2px solid #C49A2C" : "2px solid rgba(255,255,255,.2)",
                      background: form.volumen === opt.val ? "#C49A2C" : "transparent",
                    }}
                  >
                    {form.volumen === opt.val && (
                      <div className="w-1.5 h-1.5 rounded-full bg-white" />
                    )}
                  </div>
                  <div className="flex-1">
                    <p className="text-sm font-bold text-white">{opt.label}</p>
                    <p className="text-xs" style={{ color: "rgba(255,255,255,.45)" }}>{opt.desc}</p>
                  </div>
                </label>
              ))}
            </div>
          </div>

          {/* ROI preview */}
          {form.volumen && (
            <div
              className="rounded-xl p-5"
              style={{ background: "rgba(196,154,44,.07)", border: "1px solid rgba(196,154,44,.2)" }}
            >
              <div className="flex items-center gap-2 mb-3">
                <i className="ti ti-calculator text-sm" style={{ color: "#C49A2C" }} />
                <p className="text-xs font-bold uppercase tracking-wider" style={{ color: "#C49A2C" }}>Estimación de ahorro</p>
              </div>
              {form.volumen === "1-20" && (
                <p className="text-xs leading-relaxed" style={{ color: "rgba(255,255,255,.7)" }}>
                  Con 1–20 consultas/día, estimamos <strong className="text-white">1–1.5 hs ahorradas por día</strong> y una mejora de hasta <strong className="text-white">+25% en conversión</strong> de nuevos clientes.
                </p>
              )}
              {form.volumen === "21-50" && (
                <p className="text-xs leading-relaxed" style={{ color: "rgba(255,255,255,.7)" }}>
                  Con 21–50 consultas/día, proyectamos <strong className="text-white">2–3 hs diarias liberadas</strong> y un ahorro de <strong className="text-white">ARS 80.000–120.000/mes</strong> en tiempo operativo.
                </p>
              )}
              {form.volumen === "51-150" && (
                <p className="text-xs leading-relaxed" style={{ color: "rgba(255,255,255,.7)" }}>
                  Con 51–150 consultas/día, el bot puede gestionar <strong className="text-white">más del 80% sin intervención humana</strong>. Ahorro estimado: <strong className="text-white">ARS 180.000–300.000/mes</strong>.
                </p>
              )}
              {form.volumen === "150+" && (
                <p className="text-xs leading-relaxed" style={{ color: "rgba(255,255,255,.7)" }}>
                  Con más de 150 consultas/día, necesitás automatización urgente. Proyectamos <strong className="text-white">más de ARS 400.000/mes ahorrados</strong> y una reducción de carga del equipo de <strong className="text-white">70–90%</strong>.
                </p>
              )}
            </div>
          )}

          {/* Submit */}
          <button
            type="submit"
            disabled={!valid}
            className="w-full flex items-center justify-center gap-2 py-3.5 rounded-xl text-sm font-bold transition-all"
            style={{
              background: valid ? "#C49A2C" : "rgba(196,154,44,.25)",
              color: valid ? "#07102A" : "rgba(255,255,255,.3)",
              cursor: valid ? "pointer" : "not-allowed",
            }}
          >
            <i className="ti ti-brand-whatsapp text-base" />
            Pedir mi diagnóstico gratuito
          </button>
          <p className="text-center text-[11px]" style={{ color: "rgba(255,255,255,.3)" }}>
            Te contactamos por WhatsApp en menos de 2 hs hábiles · Sin compromiso
          </p>
        </div>
      </form>
    </div>
  );
}

